// Render your table
const ReportView = () => {
    return (
          <Table
            width={1200}
            height={450}
            headerHeight={20}
            rowHeight={50}
            rowCount={list.length}
            rowGetter={({ index }) => list[index]}
          >
            <Column
              label='Name'
              dataKey='name'
              width={100}
            />
            <Column
              label='Gender'
              dataKey='gender'
              width={60}
            />
            <Column
              label='Age'
              dataKey='age'
              width={60}
            />
            <Column
              label='birthday'
              dataKey='birthDate'
              width={70}
            />
            <Column
              label='Address'
              dataKey='address'
              width={150}
            />
            <Column
              label='Phone'
              dataKey='phone'
              width={70}
              disableSort={true}
            />
            <Column
              label='E-mail'
              dataKey='email'
              width={70}
              disableSort={true}
            />
          </Table>
      )
  }

  export default ReportView;
